import{_ as t,o as e,c as r,S as n}from"./chunks/framework.C6RQlTYc.js";const p=JSON.parse('{"title":"深度学习","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_3-deep_learning.md","filePath":"直击概念/17ai/s_ai_3-deep_learning.md","lastUpdated":1778207238000}'),l={name:"直击概念/17ai/s_ai_3-deep_learning.md"};function i(o,a,d,s,h,c){return e(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="深度学习" tabindex="-1">深度学习 <a class="header-anchor" href="#深度学习" aria-label="Permalink to &quot;深度学习&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>深度学习（Deep Learning）是机器学习的一个子集，核心特征是使用<strong>多层神经网络</strong>（深度神经网络）自动从数据中提取层级化特征。与传统机器学习需要人工设计特征不同，深度学习能<strong>端到端地</strong>从原始数据中学习。</p><p>深度学习的&quot;深度&quot;指的是网络中隐藏层的数量——层数越多，模型能学习到的抽象层次越丰富。</p><h2 id="核心架构" tabindex="-1">核心架构 <a class="header-anchor" href="#核心架构" aria-label="Permalink to &quot;核心架构&quot;">​</a></h2><h3 id="dnn-深度神经网络-全连接网络" tabindex="-1">DNN（深度神经网络 / 全连接网络） <a class="header-anchor" href="#dnn-深度神经网络-全连接网络" aria-label="Permalink to &quot;DNN（深度神经网络 / 全连接网络）&quot;">​</a></h3><p>每一层神经元与下一层全部相连。适合结构化数据（表格数据），但在图像和文本领域已被更优架构替代。</p><h3 id="cnn-卷积神经网络" tabindex="-1">CNN（卷积神经网络） <a class="header-anchor" href="#cnn-卷积神经网络" aria-label="Permalink to &quot;CNN（卷积神经网络）&quot;">​</a></h3><p>通过<strong>卷积核</strong>在输入上滑动提取局部特征，核心组件包括卷积层、池化层、全连接层。</p><ul><li>擅长处理图像、视频等网格结构数据</li><li>代表模型：ResNet、VGG、EfficientNet</li><li>关键特性：参数共享、平移不变性</li></ul><h3 id="rnn-循环神经网络" tabindex="-1">RNN（循环神经网络） <a class="header-anchor" href="#rnn-循环神经网络" aria-label="Permalink to &quot;RNN（循环神经网络）&quot;">​</a></h3><p>处理<strong>序列数据</strong>的网络，通过隐藏状态传递上文信息。</p><ul><li>擅长文本、时间序列等顺序数据</li><li>核心问题：长序列导致的梯度消失/爆炸</li><li>改进变体：LSTM（长短期记忆）、GRU（门控循环单元）</li></ul><h3 id="transformer" tabindex="-1">Transformer <a class="header-anchor" href="#transformer" aria-label="Permalink to &quot;Transformer&quot;">​</a></h3><p>2017 年提出的架构，用<strong>自注意力机制</strong>完全替代了 RNN 的循环结构，已成为当前大语言模型的标准架构。详见 Transformer 章节。</p><h2 id="深度学习-vs-浅层学习" tabindex="-1">深度学习 vs 浅层学习 <a class="header-anchor" href="#深度学习-vs-浅层学习" aria-label="Permalink to &quot;深度学习 vs 浅层学习&quot;">​</a></h2><table><thead><tr><th>维度</th><th>传统机器学习</th><th>深度学习</th></tr></thead><tbody><tr><td>特征工程</td><td>需要人工设计</td><td>自动学习特征</td></tr><tr><td>数据量需求</td><td>较少</td><td>大量</td></tr><tr><td>算力需求</td><td>低</td><td>高</td></tr><tr><td>可解释性</td><td>较好</td><td>较差（黑箱）</td></tr><tr><td>性能上限</td><td>有限</td><td>随数据规模持续提升</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>CNN 和 RNN 各适合处理什么类型的数据？</li><li>深度学习为什么需要大量数据？</li><li>你在前端用过深度学习模型吗？如何部署？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://www.deeplearningbook.org/" target="_blank" rel="noreferrer">Deep Learning - Ian Goodfellow</a></li><li><a href="http://neuralnetworksanddeeplearning.com/" target="_blank" rel="noreferrer">Neural Networks and Deep Learning - Michael Nielsen</a></li></ul>',21)])])}const f=t(l,[["render",i]]);export{p as __pageData,f as default};
